def _write_cfg(tmp_path: Path, host: str = "127.0.0.1") -> Path:
    cfg = tmp_path / "config.json"
    cfg.write_text(
        json.dumps(
            {
                "host": host,
                "port": 0,
                "credentials_path": str(tmp_path / "creds.json"),
                "fetch_ttl_seconds": 30,
                "fetch_timeout_seconds": 5,
                "max_backoff_seconds": 60,
                "log_level": "INFO",
            }
        ),
        encoding="utf-8",
    )
    return cfg


class TestParseArgs:
    def test_required_config(self) -> None:
        with pytest.raises(SystemExit):
            _parse_args([])

    def test_minimum_args(self, tmp_path: Path) -> None:
        ns = _parse_args(["--config", str(tmp_path / "c.json")])
        assert ns.config == tmp_path / "c.json"
        assert ns.debug is False
        assert ns.quiet is False
        assert ns.log_file is None
        assert ns.dryrun is False

    def test_all_flags(self, tmp_path: Path) -> None:
        ns = _parse_args(
            [
                "--config",
                str(tmp_path / "c.json"),
                "--debug",
                "--quiet",
                "--log-file",
                str(tmp_path / "out.log"),
                "--dryrun",
            ]
        )
        assert ns.debug is True
        assert ns.quiet is True
        assert ns.log_file == tmp_path / "out.log"
        assert ns.dryrun is True

    def test_short_quiet(self, tmp_path: Path) -> None:
        ns = _parse_args(["--config", str(tmp_path / "c.json"), "-q"])
        assert ns.quiet is True


