class TestConfigureLogging:
    def test_file_handler_added(self, tmp_path: Path) -> None:
        log_file = tmp_path / "out.log"
        # Reset root logger handlers between tests to avoid leakage.
        root = logging.getLogger()
        original_handlers = list(root.handlers)
        original_excepthook = sys.excepthook
        try:
            for h in original_handlers:
                root.removeHandler(h)
            _configure_logging(level=logging.INFO, log_file=log_file)
            handler_types = {type(h).__name__ for h in root.handlers}
            assert "FileHandler" in handler_types
            assert sys.excepthook is not original_excepthook
        finally:
            for h in list(root.handlers):
                root.removeHandler(h)
            for h in original_handlers:
                root.addHandler(h)
            sys.excepthook = original_excepthook


